    QuizQuestion(questionEn: '"He has been doing it since two years." — Correct it.',questionHi: '"He has been doing it since two years."',options: ['since → for','two → 2','doing → do','No error'],correctIndex: 0,explanation: '"Since" = specific point of time. "For" = duration/period. "two years" is a duration → use "for". "He has been doing it for two years."'),
