  ];

  static const List<QuizQuestion> ex1BQuestions = [
    QuizQuestion(questionEn: '"He died from Cancer." — Correct it.',questionHi: '"He died from Cancer."',options: ['from → of','from → with','from → by','No error'],correctIndex: 0,explanation: '"Die of" = disease/illness. "Die from" = wounds/injuries. Cancer is a disease → "He died of Cancer."'),
    QuizQuestion(questionEn: '"The director and the producer is dead." — Correct it.',questionHi: '"The director and the producer is dead." — Why?',options: ['is → are (two separate persons — both have "the")','is → were','is → has been','No error'],correctIndex: 0,explanation: 'When both nouns have "the" separately → two different persons → plural verb. "The director and the producer are dead."'),
    QuizQuestion(questionEn: '"Mr. Kumar is my English Teacher." — Correct it.',questionHi: '"Mr. Kumar is my English Teacher."',options: ['English Teacher → teacher of English','English Teacher → English teacher','No change needed','English Teacher → English\'s teacher'],correctIndex: 0,explanation: 'Subject teacher rule: "my teacher of English/Maths/Science" — NOT "my English teacher". "Mr. Kumar is my teacher of English."'),
    QuizQuestion(questionEn: '"Unless you don\'t go there, nothing will change." — Correct it.',questionHi: '"Unless you don\'t go there, nothing will change."',options: ['don\'t go → go (unless already has negative meaning)','Unless → If','Unless → Until','No error'],correctIndex: 0,explanation: '"Unless" already means "if...not". So adding "don\'t" is double negative. "Unless you go there, nothing will change."'),
