  ];

  static const List<QuizQuestion> ex2AQuestions = [
    QuizQuestion(questionEn: '"I am enjoying." — Correct it.',questionHi: '"I am enjoying." — सही करें।',options: ['enjoying → enjoy myself','Add "myself" — enjoy is a reflexive verb','enjoying → enjoyed','No error'],correctIndex: 1,explanation: '"Enjoy" is reflexive — always needs an object. "I am enjoying myself." Similarly: "I avail myself."'),
    QuizQuestion(questionEn: '"Any of the two girls can do this work." — Correct it.',questionHi: '"Any of the two girls can do this work."',options: ['Any → Either (for two)','Any → Neither','Any → Both','No error'],correctIndex: 0,explanation: '"Either" = for exactly two choices. "Any" = for three or more. "Either of the two girls can do this work."'),
