    QuizQuestion(questionEn: '"I prefer tea to coffee." — Correct it.',questionHi: '"I prefer tea to coffee."',options: ['to → over','No error — prefer + noun + to is correct','to → than','I prefer → I would prefer'],correctIndex: 1,explanation: '"Prefer + noun + to" = CORRECT. "I prefer tea to coffee." ✅ But "I prefer singing over dancing" (gerund) → "I prefer singing to dancing."'),
